insert into invoices (
  utility_account_id, property_id, vendor_id, gl_account_id,
  invoice_number, invoice_date, service_period_start, service_period_end,
  current_charges, total_amount_due, gl_coding,
  status, source, source_reference,
  submitted_at, approved_at, sage_posted_at,
  exclude_from_baseline
)
select
  ua.id,
  p.id,
  v.id,
  g.id,
  s.source_ref,
  make_date(s.year, s.month, 15),
  make_date(s.year, s.month, 1),
  (make_date(s.year, s.month, 1) + interval '1 month' - interval '1 day')::date,
  s.amount,
  s.amount,
  '500-' || s.property_code || '-' || s.gl_code || '.00',
  'posted_to_sage'::invoice_status,
  'manual'::bill_source,
  s.source_ref,
  make_date(s.year, s.month, 15)::timestamptz,
  make_date(s.year, s.month, 15)::timestamptz,
  make_date(s.year, s.month, 15)::timestamptz,
  false
from seed s
join properties  p on p.code        = s.property_code
join vendors     v on v.short_name  = s.vendor_short
join gl_accounts g on g.code        = s.gl_code
join utility_accounts ua on ua.vendor_id = v.id
                         and ua.account_number = s.account_number
                         and (ua.meter_id is not distinct from nullif(s.meter_id, ''))
                         and ua.gl_account_id = g.id;


-- Sanity check: verify cumulative row counts after parts a-d ----------------

do $$
declare
  v_inv_count int;
  v_ua_count  int;
  v_vend_count int;
begin
  select count(*) into v_inv_count
    from invoices where source_reference like 'historical-%';
  select count(*) into v_ua_count
    from utility_accounts where id in (
      select distinct utility_account_id from invoices
       where source_reference like 'historical-%'
    );
  select count(*) into v_vend_count
    from vendors where short_name like 'HIST-%';

  raise notice 'Migration 0015 complete: % invoices, % utility_accounts, % vendors', v_inv_count, v_ua_count, v_vend_count;

  if v_inv_count < 11362 then
    raise exception 'Expected ~11412 historical invoices, got %', v_inv_count;
  end if;
  if v_vend_count < 155 then
    raise exception 'Expected ~160 historical vendors, got %', v_vend_count;
  end if;
end $$;
